-- Data for memos (13 rows)
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('e4b12cda-7c55-45d5-aaea-685569bbdda2', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Rahul Sharma', 'Q1 2026 Company Goals', 'We are excited to share our Q1 2026 objectives. Our primary focus areas include revenue growth, product innovation, and team expansion. Each department has aligned their goals with these company-wide priorities.', 'Overview of our key objectives for the first quarter', 'All', 'high', 'published', 156, '2026-01-05T00:00:00+00:00', '2026-02-06T09:47:05.878882+00:00', '2026-02-20T07:29:39.054661+00:00', '[]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('4ca0a954-649b-4a23-9168-8bb8a12e1c0a', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Security Team', 'Security Awareness Training', 'All employees must complete the annual security awareness training by February 28th. This is a compliance requirement. Please access the training portal from the HR dashboard.', 'Mandatory cybersecurity training reminder', 'IT', 'high', 'published', 67, '2026-02-03T00:00:00+00:00', '2026-02-06T09:47:05.878882+00:00', '2026-02-20T07:29:39.054661+00:00', '[]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('0fe75a01-b9f7-4abc-9071-5b1c5db1a4a7', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Engineering', 'Product Roadmap Draft', 'This draft outlines our product roadmap for 2026. Key features include mobile app launch, API v2, and analytics dashboard improvements. Please provide feedback by EOD Friday.', 'Internal review of upcoming features', 'Product', 'medium', 'draft', 0, NULL, '2026-02-06T09:47:05.878882+00:00', '2026-02-20T07:29:39.054661+00:00', '[]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('9502618a-d74e-4613-84c0-a307e4e6ea45', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Rajesh Kumar', 'Security Advisory: Phishing Alert', 'Multiple phishing attempts have been detected targeting our employees. Please do not click on suspicious links or download attachments from unknown senders. Report any suspicious emails to security@grx10.com immediately.', 'Phishing alert: avoid suspicious links, report to security team.', 'IT', 'high', 'published', 120, '2026-02-12T00:00:00+00:00', '2026-02-17T06:53:38.801043+00:00', '2026-02-20T07:29:39.054661+00:00', '["All Departments"]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('07eaac43-07d5-4140-a418-0ce34ae40f12', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Rajesh Kumar', 'Sprint Planning Update - February 2026', 'Please note the following updates for our February sprint cycle. All team members are expected to complete their assigned tasks by February 28th. Daily standups will be at 10 AM IST. Reach out to your team leads for any blockers.', 'February sprint updates: tasks due by 28th, standups at 10 AM IST.', 'Engineering', 'medium', 'published', 0, '2026-02-17T07:02:07.536818+00:00', '2026-02-17T07:02:07.536818+00:00', '2026-02-20T07:29:39.054661+00:00', '["Engineering Team","Amit Patel","Neha Gupta"]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('aad714da-2053-4bb4-bea2-cdd67eaff78d', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Priya Patel', 'New Leave Policy Update', 'Effective February 1st, we are implementing a more flexible leave policy. Employees can now carry forward up to 10 unused leave days to the next year. Remote work days will not count against your leave balance.', 'Important changes to our leave management system', 'HR', 'medium', 'published', 90, '2026-01-28T00:00:00+00:00', '2026-02-06T09:47:05.878882+00:00', '2026-02-20T07:29:39.054661+00:00', '[]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
INSERT INTO public."memos" ("id", "user_id", "author_name", "title", "content", "excerpt", "department", "priority", "status", "views", "published_at", "created_at", "updated_at", "recipients", "subject", "attachment_url", "reviewer_notes", "organization_id", "reviewed_by") VALUES ('f9084e3b-58cc-440c-baab-3e0a0f86af44', 'c9dd5f73-f09f-4a93-9542-5473351fab37', 'Amit Kumar', 'Office Renovation Schedule', 'The office renovation will begin on February 15th and is expected to complete by March 10th. During this period, we encourage work-from-home arrangements. Meeting rooms A and B will remain accessible.', 'Upcoming changes to our workspace', 'Operations', 'low', 'published', 46, '2026-02-01T00:00:00+00:00', '2026-02-06T09:47:05.878882+00:00', '2026-02-24T10:34:50.985593+00:00', '[]'::jsonb, NULL, NULL, NULL, '00000000-0000-0000-0000-000000000001', NULL);
